
function addMenuTogglerEventListener(){const mainNavElement=document.querySelector('.main-nav');const menuToggleElement=mainNavElement.querySelector('.main-nav__toggle');const menuListElements=mainNavElement.querySelectorAll('.main-nav__list');function changeButton(button){button.classList.toggle('main-nav__toggle--open');button.classList.toggle('main-nav__toggle--close');}
function changeMenuState(menuList){menuList.classList.toggle('main-nav__list--closed');menuList.classList.toggle('main-nav__list--opened');}
function changeButtonAriaLabel(button,menuList){if(menuList.classList.contains('main-nav__list--opened')){button.setAttribute('aria-label','Закрыть меню');}else{button.setAttribute('aria-label','Открыть меню');}}
function onButtonCloseClick(){changeButton(menuToggleElement);menuListElements.forEach((menuList)=>{changeMenuState(menuList);changeButtonAriaLabel(menuToggleElement,menuList);});}
menuToggleElement.addEventListener('click',()=>onButtonCloseClick());}
addMenuTogglerEventListener();